271	/**
272	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
273	 *
274	 * `linkId` (when set) names a `link_model` element in the host whose source
275	 * model contains the monitored element; intra-host monitors omit it.
276	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
277	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
278	 * counter at the moment of the copy; the BumpMonitoredRevisions command
279	 * compares it against the latest revision and flags drift.
280	 *
281	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
282	 * persist on the host element so the constraint evaluator can emit a
283	 * `monitored_source_drift` advisory without needing live source access.
284	 */
285	export type MonitorSource = {
286	  linkId?: string | null;
287	  elementId: string;
288	  sourceRevisionAtCopy: number;
289	  drifted?: boolean;
290	  driftedFields?: string[];
291	};
