  | {
      /** ANN-01 — view-local 2D filled region (annotation only). */
      kind: 'detail_region';
      id: string;
      hostViewId: string;
      boundaryMm: XY[];
      fillColour?: string;
      fillPattern?: 'solid' | 'hatch_45' | 'hatch_90' | 'crosshatch' | 'dots';
      strokeMm?: number;
